        }

        public override async Task Validation(ProbationPeriod item, Result<ProbationPeriod> executionResult)
        {
            if (await UOW.GetRepositoryAsync<ProbationPeriod>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(ProbationPeriod.Name), "Name already exists"));
            }
        }
        public override async Task<ProbationPeriod> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<ProbationPeriod>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<ProbationPeriod>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<ProbationPeriod>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<ProbationPeriod>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<ProbationPeriod>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
